worked_example.final_code:
import java.util.*;

public class WildcardUtils {
    // Producer: ? extends — read as Number
    static double sumAll(List<? extends Number> nums) {
        double total = 0;
        for (Number n : nums) total += n.doubleValue();
        return total;
    }

    // Consumer: ? super — add Strings
    static void fillDefaults(List<? super String> target, String... defaults) {
        for (String d : defaults) target.add(d);
    }

    // PECS: src=producer (extends), dest=consumer (super)
    static <T> void copy(List<? super T> dest, List<? extends T> src) {
        for (T element : src) dest.add(element);
    }

    // Unbounded: just need size
    static void printInfo(List<?> list) {
        System.out.println("Size: " + list.size() + ", items: " + list);
    }

    public static void main(String[] args) {
        // sumAll — any numeric list
        System.out.println(sumAll(Arrays.asList(10, 20, 30)));       // 60.0
        System.out.println(sumAll(Arrays.asList(1.5, 2.5, 3.0)));   // 7.0
        System.out.println(sumAll(Arrays.asList(100L, 200L)));       // 300.0

        // fillDefaults — any list of String or supertype
        List<String> names = new ArrayList<>();
        fillDefaults(names, "Aisha", "Raj", "Priya");
        System.out.println(names);

        // copy
        List<Integer> ints    = Arrays.asList(1, 2, 3);
        List<Number>  numbers = new ArrayList<>();
        copy(numbers, ints);  // T=Integer
        System.out.println(numbers);

        // printInfo — unbounded
        printInfo(names);
        printInfo(numbers);
    }
}
